public static long solve(long[] nums) {
    int n = nums.length;
    Arrays.sort(nums);

    // For each possible k, check if we can sort the array using swaps with AND equal to k
    for (int k = n - 1; k >= 0; k--) {
        boolean[] canSort = new boolean[n];
        Arrays.fill(canSort, true);

        for (int i = 0; i < n; i++) {
            if (!canSort[i]) continue;

            for (int j = i + 1; j < n; j++) {
                if (!canSort[j]) continue;

                if ((nums[i] & nums[j]) == k) {
                    canSort[j] = false;
                    break;
                }
            }
        }

        boolean isSorted = true;
        for (int i = 0; i < n - 1; i++) {
            if (nums[i] > nums[i + 1]) {
                isSorted = false;
                break;
            }
        }

        if (isSorted) {
            return k;
        }
    }

    return 0;
