public static long solve(long[] nums) {
    int n = nums.length;
    boolean[][] canSwap = new boolean[n][n];

    // Precompute all possible pairs that can be swapped
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i != j && (nums[i] & nums[j]) >= 0) {
                canSwap[i][j] = true;
                canSwap[j][i] = true;
            }
        }
    }

    // Check for each possible k in descending order
    for (long k = (1L << 60) - 1; k >= 0; k--) {
        // Check if we can sort the array with this k
        if (canSortWithK(nums, canSwap, k)) {
            return k;
        }
    }

    return 0;
}

private static boolean canSortWithK(long[] nums, boolean[][] canSwap, long k) {
    int n = nums.length;
    boolean[] visited = new boolean[n];

    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            // Perform BFS to find all nodes reachable from i
            Queue<Integer> queue = new LinkedList<>();
            queue.add(i);
            visited[i] = true;

            while (!queue.isEmpty()) {
                int curr = queue.poll();
                for (int neighbor = 0; neighbor < n; neighbor++) {
                    if (!visited[neighbor] && canSwap[curr][neighbor]) {
                        visited[neighbor] = true;
                        queue.add(neighbor);
                    }
                }
            }
        }
    }

    // Check if the array can be sorted with the current k
    for (int i = 0; i < n - 1; i++) {
        if (nums[i] > nums[i + 1]) {
            return false;
        }
    }
    return true;
}
