public class Solution {
    public static long solve(long[] nums) {
        int n = nums.length;
        Arrays.sort(nums);

        Map<Long, List<Integer>> bitMap = new HashMap<>();

        for (int i = 0; i < n; i++) {
            long num = nums[i];
            long mask = 0;
            for (int j = 0; j < 64; j++) {
                if ((num & (1L << j)) != 0) {
                    mask |= (1L << j);
                }
            }
            bitMap.computeIfAbsent(mask, k -> new ArrayList<>()).add(i);
        }

        long maxK = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                long k = nums[i] & nums[j];
                if (k > maxK) {
                    maxK = k;
                }
            }
        }

        return maxK;
    }
